final class PromoManager {
    static let shared = PromoManager()
    
    private let userDefaults = UserDefaults.standard
    private let appliedPromoCodesKey = "appliedPromoCodes"
    private let pendingPromoKey = "pendingPromo"
    
    private init() {}
    
    struct Promo: Codable, Equatable {
        let code: String
        let discount: Int
    }
    
    func handleUniversalLink(_ url: URL) {
        guard url.scheme?.lowercased() == "https",
              url.host?.lowercased() == "myapp.com",
              url.path == "/promo" else {
            return
        }
        
        let components = URLComponents(url: url, resolvingAgainstBaseURL: false)
        let items = components?.queryItems ?? []
        
        guard let code = items.first(where: { $0.name == "code" })?.value,
              !code.isEmpty,
              let discountString = items.first(where: { $0.name == "discount" })?.value,
              let discount = Int(discountString),
              (1...100).contains(discount) else {
            return
        }
        
        let promo = Promo(code: code, discount: discount)
        applyPromoToCurrentUser(promo)
    }
    
    private func applyPromoToCurrentUser(_ promo: Promo) {
        var appliedCodes = Set(userDefaults.stringArray(forKey: appliedPromoCodesKey) ?? [])
        guard !appliedCodes.contains(promo.code) else { return }
        
        appliedCodes.insert(promo.code)
        userDefaults.set(Array(appliedCodes), forKey: appliedPromoCodesKey)
        userDefaults.set(promo.discount, forKey: "\(promo.code)_discount")
        userDefaults.set(promo.code, forKey: pendingPromoKey)
        
        NotificationCenter.default.post(name: .promoApplied, object: promo)
    }
    
    func currentPromo() -> Promo? {
        guard let code = userDefaults.string(forKey: pendingPromoKey) else { return nil }
        let discount = userDefaults.integer(forKey: "\(code)_discount")
        guard discount > 0 else { return nil }
        return Promo(code: code, discount: discount)
    }
    
    func clearCurrentPromo() {
        userDefaults.removeObject(forKey: pendingPromoKey)
    }
}

