final class UserAccount {
    let userID: String
    var discountPercentage: Int = 0
    var appliedPromos: [String] = []
    
    init(userID: String) {
        self.userID = userID
    }
    
    func applyPromo(code: String, discount: Int) {
        guard !appliedPromos.contains(code) else { return }
        appliedPromos.append(code)
        discountPercentage = max(discountPercentage, discount)
    }
}

final class AccountService {
    static let shared = AccountService()
    private init() {}
    
    private(set) var currentUser: UserAccount?
    
    func signIn(userID: String) {
        currentUser = UserAccount(userID: userID)
        if let promo = PromoManager.shared.currentPromo() {
            currentUser?.applyPromo(code: promo.code, discount: promo.discount)
            PromoManager.shared.clearCurrentPromo()
